/**
 * Handles user registration form submission with validation.
 * @param {HTMLFormElement} form - The form element to submit.
 * @returns {boolean} - Returns false if validation fails, true if valid.
 */
function handleRegistrationSubmit(form) {
  // Prevent default submission
  form.addEventListener('submit', function (event) {
    event.preventDefault();

    const emailInput = form.querySelector('#email');
    const passwordInput = form.querySelector('#password');
    const usernameInput = form.querySelector('#username');

    const email = emailInput.value.trim();
    const password = passwordInput.value;
    const username = usernameInput.value.trim();

    const errors = [];

    // 1. Validate Email (RFC 5322 compliant regex)
    const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
    if (!emailRegex.test(email)) {
      errors.push('Error: Invalid email format. Please enter a valid email address.');
    }

    // 2. Validate Password (Min 8 chars, at least 1 digit)
    const passwordRegex = /^(?=.*\d).{8,}$/;
    if (!passwordRegex.test(password)) {
      errors.push('Error: Password must be at least 8 characters long and contain at least one number.');
    }

    // 3. Validate Username (Alphanumeric only)
    const usernameRegex = /^[a-zA-Z0-9]+$/;
    if (!usernameRegex.test(username)) {
      errors.push('Error: Username must contain only alphanumeric characters.');
    }

    // Handle Errors
    if (errors.length > 0) {
      // Clear previous error messages if any (assuming a container with id="error-container")
      const errorContainer = form.querySelector('#error-container');
      if (errorContainer) {
        errorContainer.innerHTML = errors.map(err => `<p>${err}</p>`).join('');
        errorContainer.style.display = 'block';
      } else {
        // Fallback: alert if no container exists
        alert(errors.join('\n'));
      }
      return false;
    }

    // Validation Passed
    if (errorContainer) {
      errorContainer.innerHTML = '';
      errorContainer.style.display = 'none';
    }

    // Proceed with actual submission (e.g., AJAX or native submit)
    // For this example, we simulate a successful submission
    console.log('Form is valid. Submitting data...');
    // form.submit(); // Uncomment to allow native submission
    return true;
  });
}

// Usage Example:
// document.addEventListener('DOMContentLoaded', () => {
