const https = require('https');
const { URL } = require('url');

const API_ENDPOINT = 'https://api.example.com/users/{id}';
const RETRY_COUNT = 3;
const RETRY_DELAY_MS = 1000;

// Input Validation
function isValidUserId(userId) {
  const num = Number(userId);
  return Number.isInteger(num) && num > 0;
}

// Response Validation
function validateResponse(data) {
  if (typeof data !== 'object' || data === null) {
    throw new Error('Invalid response structure: expected an object');
  }
  if (typeof data.id !== 'number' || !Number.isInteger(data.id)) {
    throw new Error('Invalid response structure: "id" must be an integer');
  }
  if (typeof data.name !== 'string') {
    throw new Error('Invalid response structure: "name" must be a string');
  }
  if (typeof data.email !== 'string') {
    throw new Error('Invalid response structure: "email" must be a string');
  }
  return true;
}

// HTTP Request with Retry Logic
function fetchUserData(userId) {
  return new Promise((resolve, reject) => {
    let attempts = 0;

    const makeRequest = () => {
      attempts++;
      const url = API_ENDPOINT.replace('{id}', userId);
      const parsedUrl = new URL(url);

      const req = https.get(url, {
        headers: {
          'Accept': 'application/json'
        }
      }, (res) => {
        let data = '';

        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          if (res.statusCode >= 500 || res.statusCode === 408 || res.statusCode === 429) {
            // Transient error
            if (attempts < RETRY_COUNT) {
              console.log(`Transient error (${res.statusCode}). Retrying... (${attempts}/${RETRY_COUNT})`);
              setTimeout(makeRequest, RETRY_DELAY_MS);
              return;
            } else {
              reject(new Error(`Max retries exceeded. Final status: ${res.statusCode}`));
              return;
            }
          }

          if (res.statusCode !== 200) {
            reject(new Error(`HTTP Error: ${res.statusCode}`));
            return;
          }

          try {
            const jsonData = JSON.parse(data);
            validateResponse(jsonData);
            resolve(jsonData);
          } catch (err) {
            reject(new Error(`Validation Error: ${err.message}`));
          }
        });
      });

      req.on('error', (err) => {
        if (attempts < RETRY_COUNT) {
          console.log(`Network error. Retrying... (${attempts}/${RETRY_COUNT})`);
          setTimeout(makeRequest, RETRY_DELAY_MS);
        } else {
          reject(new Error(`Network Error: ${err.message}`));
        }
      });
    };

    makeRequest();
  });
}

// Main Execution
async function main() {
  const userId = process.argv[2];

  if (!userId || !isValidUserId(userId)) {
    console.error('Error: User ID must be a valid positive integer.');
    console.error('Usage: node script.js <user_id>');
    process.exit(1);
  }

  try {
    const userData = await fetchUserData(userId);
    console.log('User Data Retrieved Successfully:');
    console.log(JSON.stringify(userData, null, 2));
  } catch (error) {
    console.error('Failed to fetch user data:', error.message);
    process.exit(1);
  }
}

main();
