(function() {
  'use strict';

  // Configuration
  const CONFIG = {
    polyfillUrl: 'https://cdn.jsdelivr.net/npm/promise-polyfill@8/dist/polyfill.min.js',
    timeoutMs: 5000,
    requiredFeatures: ['Promise', 'fetch']
  };

  /**
   * Validates input parameters strictly.
   * @param {Object} options - Configuration overrides
   * @returns {Object} Validated configuration
   */
  function validateInput(options) {
    if (typeof options !== 'object' || options === null) {
      throw new TypeError('Options must be a non-null object');
    }

    if (options.timeoutMs && typeof options.timeoutMs !== 'number') {
      throw new TypeError('timeoutMs must be a number');
    }

    if (options.polyfillUrl && typeof options.polyfillUrl !== 'string') {
      throw new TypeError('polyfillUrl must be a string');
    }

    return { ...CONFIG, ...options };
  }

  /**
   * Checks if a specific feature is missing in the current environment.
   * @param {string} featureName - The feature to check (e.g., 'Promise')
   * @returns {boolean} True if missing, false otherwise.
   */
  function isFeatureMissing(featureName) {
    if (typeof window === 'undefined') {
      // Node.js environment check
      return !global[featureName];
    }
    return typeof window[featureName] === 'undefined';
  }

  /**
   * Loads a script with a timeout and error handling.
   * @param {string} src - Script source URL
   * @param {number} timeout - Timeout in milliseconds
   * @returns {Promise<void>}
   */
  function loadScriptWithTimeout(src, timeout) {
    return new Promise((resolve, reject) => {
      const script = document.createElement('script');
      script.src = src;
      script.async = true;

      const timeoutId = setTimeout(() => {
        script.onerror = null;
        script.onload = null;
        reject(new Error(`Network timeout: Failed to load ${src} within ${timeout}ms`));
      }, timeout);

      script.onload = () => {
        clearTimeout(timeoutId);
        resolve();
      };

      script.onerror = () => {
        clearTimeout(timeoutId);
        reject(new Error(`Network error: Failed to load ${src}`));
      };

      document.head.appendChild(script);
    });
  }

  /**
   * Main diagnostic and fallback execution.
   */
  async function runDiagnostic() {
    try {
      // 1. Validate Environment & Input
      const config = validateInput({});

      console.log('[Diagnostic] Starting environment check...');

      // 2. Check for specific missing polyfills
      const missingFeatures = config.requiredFeatures.filter(feature => isFeatureMissing(feature));

      if (missingFeatures.length === 0) {
        console.log('[Diagnostic] All required features are present. No action needed.');
        return;
      }

      console.warn(`[Diagnostic] Missing features detected: ${missingFeatures.join(', ')}`);

      // 3. Implement Fallback Mechanism
      if (missingFeatures.includes('Promise')) {
        console.log('[Fallback] Loading Promise polyfill...');
        try {
          await loadScriptWithTimeout(config.polyfillUrl, config.timeoutMs);

          // Verify load success
          if (isFeatureMissing('Promise')) {
            throw new Error('Polyfill loaded but Promise is still undefined. Fallback failed.');
          }

          console.log('[Fallback] Promise polyfill successfully applied.');
        } catch (err) {
          console.error('[Fallback Error]', err.message);
          // Final fallback: Disable async/await dependent features gracefully
          console.warn('[Fallback] Disabling async operations due to polyfill failure.');
          window.PROMISE_POLYFILL_FAILED = true;
        }
      }

      // 4. Re-validate after load
      const remainingMissing = config.requiredFeatures.filter(feature => isFeatureMissing(feature));
      if (remainingMissing.length > 0) {
        console.error(`[Diagnostic] Critical failure: ${remainingMissing.join(', ')} remain missing.`);
      } else {
        console.log('[Diagnostic] Environment validated and patched successfully.');
      }

    } catch (error) {
      // Global Error Handler for the script itself
      console.error('[Diagnostic Script Fatal Error]', error);
      if (window.PROMISE_POLYFILL_FAILED) {
        // Trigger a user-friendly UI fallback if available
        if (document.getElementById('app-root')) {
          document.getElementById('app-root').innerHTML = '<div style="color:red">Application failed to initialize due to browser compatibility issues.</div>';
        }
      }
    }
  }

  // Execute immediately if in browser context
  if (typeof window !== 'undefined') {
    // Ensure DOM is ready or run immediately if head is available
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', runDiagnostic);
    } else {
      runDiagnostic();
    }
  }

  // Export for Node.js testing if needed
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = { runDiagnostic, validateInput, isFeatureMissing };
  }

})();
