// Runtime: Node.js 18+ (Compatible with AWS Lambda, Cloudflare Workers, etc.)

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Securely logs errors without exposing PII.
 * @param {string} message - The error message.
 * @param {object} context - Additional context (sanitized).
 */
function logSecureError(message, context = {}) {
  const sanitizedContext = {
    timestamp: new Date().toISOString(),
    requestId: context.requestId || 'unknown',
    emailMasked: context.email ? context.email.replace(/(.{2}).+@(.+)/, '$1***@$2') : null,
    errorType: context.errorType || 'Unknown'
  };

  // In production, replace console.error with a secure logging service (e.g., CloudWatch, Datadog)
  console.error(`[SECURITY_LOG] ${message}`, JSON.stringify(sanitizedContext));
}

/**
 * Validates email format.
 * @param {string} email - The email to validate.
 * @returns {boolean}
 */
function isValidEmail(email) {
  return typeof email === 'string' && EMAIL_REGEX.test(email);
}

/**
 * Generates browser-specific troubleshooting steps.
 * @returns {object}
 */
function getTroubleshootingSteps() {
  return {
    chrome: [
      "Clear browser cache and cookies (Ctrl+Shift+Delete).",
      "Disable browser extensions temporarily.",
      "Ensure Chrome is updated to the latest version.",
      "Try opening the login page in Incognito mode."
    ],
