const NodeCache = require('node-cache');
const { v4: uuidv4 } = require('uuid');

// Initialize cache with default TTL of 300 seconds (5 minutes)
const articleCache = new NodeCache({ stdTTL: 300, checkperiod: 60 });

/**
 * Validates and sanitizes cache keys to prevent injection attacks
 * and ensure consistency.
 * @param {string} key - The raw cache key
 * @returns {string} - Sanitized and validated key
 * @throws {Error} - If key is invalid
 */
function validateCacheKey(key) {
  if (typeof key !== 'string') {
    throw new Error('Cache key must be a string');
  }

  const trimmedKey = key.trim();

  if (trimmedKey.length === 0) {
    throw new Error('Cache key cannot be empty');
  }

  if (trimmedKey.length > 255) {
    throw new Error('Cache key exceeds maximum length of 255 characters');
  }

  // Regex to allow only alphanumeric, hyphens, underscores, and dots
  if (!/^[a-zA-Z0-9._-]+$/.test(trimmedKey)) {
    throw new Error('Cache key contains invalid characters');
  }

  return trimmedKey;
}

/**
 * Retrieves an article from cache or database.
 * Implements fallback logic for cache misses and handles errors gracefully.
 * @param {string} articleId - The unique identifier for the article
 * @param {Function} fetchFromDb - Async function to fetch data from PostgreSQL
 * @returns {Promise<Object>} - The article data
 */
async function getArticleWithCache(articleId, fetchFromDb) {
  const cacheKey = `article:${articleId}`;

  try {
    // Validate input before accessing cache
    const safeKey = validateCacheKey(cacheKey);

    // Attempt to retrieve from cache
    const cachedData = articleCache.get(safeKey);

    if (cachedData) {
      console.log(`Cache hit for article ${articleId}`);
      return cachedData;
    }

    console.log(`Cache miss for article ${articleId}, fetching from DB...`);

    // Fetch from database
    const articleData = await fetchFromDb(articleId);

    if (!articleData) {
      throw new Error(`Article ${articleId} not found in database`);
    }

    // Store in cache
    articleCache.set(safeKey, articleData);

    return articleData;

  } catch (error) {
    // Specific handling for cache misses vs system errors
    if (error.message.includes('not found')) {
      // Propagate 404 logic to the controller
      throw error;
    }

    // Log unexpected errors but do not crash the service
    console.error(`Caching error for article ${articleId}:`, error.message);

    // Fallback: Attempt direct DB fetch if cache logic fails
    try {
      return await fetchFromDb(articleId);
    } catch (dbError) {
      console.error(`Database fallback failed:`, dbError.message);
      throw new Error('Service temporarily unavailable');
    }
  }
}

