/**
 * Robust file upload function with IE11 fallback, validation, and error handling.
 * @param {File} file - The file object to upload.
 * @param {string} uploadUrl - The endpoint URL.
 * @param {Object} options - Configuration options (maxSize, allowedTypes).
 * @returns {Promise<any>} - The JSON response from the server.
 */
function uploadFile(file, uploadUrl = '/upload', options = {}) {
  const {
    maxSize = 10 * 1024 * 1024, // Default 10MB
    allowedTypes = ['image/*', 'application/pdf', 'text/plain'] // Default types
  } = options;

  // 1. Input Validation
  if (!file) {
    return Promise.reject(new Error('No file provided.'));
  }

  if (file.size > maxSize) {
    return Promise.reject(new Error(`File size exceeds limit of ${maxSize / 1024 / 1024}MB.`));
  }

  const fileType = file.type || file.name.split('.').pop();
  const isTypeAllowed = allowedTypes.some(type => {
    if (type.includes('*')) {
      const baseType = type.split('/')[0];
      return fileType.startsWith(baseType);
    }
    return fileType === type || file.type === type;
  });

  if (!isTypeAllowed) {
    return Promise.reject(new Error('File type is not allowed.'));
  }

  // 2. Feature Detection for Fetch and FormData
  const supportsFetch = typeof window !== 'undefined' && window.fetch && window.FormData;

  if (!supportsFetch) {
    // 3. Fallback for Legacy Browsers (e.g., IE11) using XMLHttpRequest
    return new Promise((resolve, reject) => {
      const xhr = new window.XMLHttpRequest();
      const formData = new window.FormData();
      formData.append('file', file);

      xhr.open('POST', uploadUrl, true);

      // Handle progress (optional but recommended)
      xhr.upload.onprogress = (event) => {
        if (event.lengthComputable) {
          const percentComplete = (event.loaded / event.total) * 100;
          console.log(`Upload progress: ${percentComplete.toFixed(2)}%`);
        }
      };

      xhr.onload = () => {
        if (xhr.status >= 200 && xhr.status < 300) {
          try {
            resolve(JSON.parse(xhr.responseText));
          } catch (e) {
            reject(new Error('Invalid JSON response from server.'));
          }
        } else {
          reject(new Error(`Upload failed with status: ${xhr.status} ${xhr.statusText}`));
        }
      };

      xhr.onerror = () => {
        reject(new Error('Network error occurred during upload.'));
      };

      xhr.ontimeout = () => {
        reject(new Error('Upload timed out.'));
      };

      xhr.send(formData);
    });
  }

  // 4. Modern Implementation using Fetch API
  return new Promise((resolve, reject) => {
    const formData = new window.FormData();
    formData.append('file', file);

    fetch(uploadUrl, {
      method: 'POST',
      body: formData
    })
      .then(response => {
        if (!response.ok) {
          throw new Error(`Server responded with status: ${response.status}`);
        }
        return response.json();
      })
      .then(data => resolve(data))
      .catch(error => {
        // Distinguish between network errors and parse errors
        if (error instanceof TypeError && error.message === 'Failed to fetch') {
          reject(new Error('Network error: Unable to reach server.'));
        } else {
          reject(error);
        }
      });
  });
}
